    def __init__(self, table: str):
        if table not in SEARCHABLE_SCHEMA:
            raise ValueError(f"Table '{table}' is not searchable.")
        self.table = table
        self.schema = SEARCHABLE_SCHEMA[table]
        self.where_clauses: list = []
        self.params: list = []
        self.order_clauses: list = []
        self.limit_val: int = DEFAULT_LIMIT
        self.offset_val: int = 0

