        from_part = psycopg2_sql.SQL(" FROM {}").format(self._ident(self.table))

        where_part = psycopg2_sql.SQL("")
        if self.where_clauses:
            where_part = psycopg2_sql.SQL(" WHERE ") + psycopg2_sql.SQL(" AND ").join(
                self.where_clauses
            )

        order_part = psycopg2_sql.SQL("")
        if not count_only and self.order_clauses:
            order_part = psycopg2_sql.SQL(" ORDER BY ") + psycopg2_sql.SQL(", ").join(
                self.order_clauses
            )

        limit_offset = psycopg2_sql.SQL("")
        if not count_only:
            limit_offset = psycopg2_sql.SQL(" LIMIT %s OFFSET %s")

        full_query = (
            select_part + from_part + where_part + order_part + limit_offset
        )

