# ---------------------------------------------------------------------------
# Value parsing helper
# ---------------------------------------------------------------------------

def _parse_filter_value(filter_input: SearchFilterInput, col_type: str):
    """Convert stringified GraphQL input values to appropriate Python types."""
    operator = filter_input.operator

    if operator in ("is_null", "is_not_null"):
        return None

    if operator in ("in", "not_in", "between"):
        raw_values = filter_input.values or []
        return [_cast(v, col_type) for v in raw_values]

    return _cast(filter_input.value, col_type)


def _cast(value, col_type):
    if value is None:
        return None
    if col_type == "integer":
        return int(value)
    if col_type == "numeric":
        return float(value)
    if col_type == "boolean":
        return value.lower() in ("true", "1", "yes", "t")
    return str(value)


