# ---------------------------------------------------------------------------

class Query(graphene.ObjectType):
    search = graphene.Field(
        SearchResult,
        table=graphene.String(required=True, description="Table to search."),
        filters=graphene.List(SearchFilterInput, default_value=[]),
        sort=graphene.List(SortInput, default_value=[]),
        pagination=PaginationInput(default_value=None),
        description="Flexible dynamic search across whitelisted tables.",
    )

    search_products = graphene.Field(
        SearchResult,
        query=graphene.String(description="Full-text search query."),
        category=graphene.String(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        is_active=graphene.Boolean(default_value=True),
        sort=graphene.List(SortInput, default_value=[]),
        pagination=PaginationInput(default_value=None),
        description="Convenience endpoint for product search.",
    )

    search_users = graphene.Field(
        SearchResult,
        query=graphene.String(description="Full-text search query."),
        is_active=graphene.Boolean(),
        sort=graphene.List(SortInput, default_value=[]),
        pagination=PaginationInput(default_value=None),
        description="Convenience endpoint for user search.",
    )

    # -- generic search resolver --

    def resolve_search(self, info, table, filters=None, sort=None, pagination=None):
        try:
            builder = DynamicSearchBuilder(table)
            schema = SEARCHABLE_SCHEMA[table]

            # Apply filters
            for f in (filters or []):
                if f.operator == "full_text":
                    builder.add_filter(f.field, f.operator, f.value)
                else:
                    col_type = schema["columns"].get(f.field, "text")
                    parsed = _parse_filter_value(f, col_type)
                    builder.add_filter(f.field, f.operator, parsed)

            # Apply sorting
            for s in (sort or []):
                builder.add_sort(s.field, s.direction)

            # Apply pagination
            if pagination:
                builder.set_pagination(
                    limit=pagination.limit or DEFAULT_LIMIT,
                    offset=pagination.offset or 0,
                )

            # Build & execute data query
            data_sql, data_params = builder.build_select(count_only=False)
            rows = execute_query(data_sql, data_params)

            # Build & execute count query
            count_sql, count_params = builder.build_select(count_only=True)
            total_count = execute_count_query(count_sql, count_params)

            items = []
            for row in rows:
                relevance = row.pop("_relevance_score", None)
                items.append(
                    SearchResultItem(
                        data=row,
                        relevance_score=float(relevance) if relevance else None,
                    )
                )

            return SearchResult(
                items=items,
                total_count=total_count,
                limit=builder.limit_val,
                offset=builder.offset_val,
                has_next_page=(builder.offset_val + builder.limit_val) < total_count,
            )
        except ValueError as e:
            raise Exception(str(e))

    # -- convenience product search resolver --

    def resolve_search_products(
        self, info, query=None, category=None, min_price=None,
        max_price=None, is_active=True, sort=None, pagination=None,
    ):
        filters = []
        if query:
            filters.append(
                SearchFilterInput(field="name", operator="full_text", value=query)
            )
        if category:
            filters.append(
                SearchFilterInput(field="category", operator="eq", value=category)
            )
        if min_price is not None:
            filters.append(
                SearchFilterInput(field="price", operator="gte", value=str(min_price))
            )
        if max_price is not None:
            filters.append(
                SearchFilterInput(field="price", operator="lte", value=str(max_price))
            )
        if is_active is not None:
            filters.append(
                SearchFilterInput(
                    field="is_active", operator="eq", value=str(is_active).lower()
                )
            )

        return Query.resolve_search(
            self, info, table="products", filters=filters, sort=sort, pagination=pagination
        )

    # -- convenience user search resolver --

    def resolve_search_users(
        self, info, query=None, is_active=None, sort=None, pagination=None
    ):
        filters = []
        if query:
            filters.append(
                SearchFilterInput(field="username", operator="full_text", value=query)
            )
        if is_active is not None:
            filters.append(
                SearchFilterInput(
                    field="is_active", operator="eq", value=str(is_active).lower()
                )
            )

        return Query.resolve_search(
            self, info, table="users", filters=filters, sort=sort, pagination=pagination
        )


