SETUP_SQL = """
-- Products table
CREATE TABLE IF NOT EXISTS products (
    id SERIAL PRIMARY KEY,
    name TEXT NOT NULL,
    description TEXT,
    category TEXT,
    price NUMERIC(10,2),
    sku TEXT,
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT NOW(),
    search_vector TSVECTOR
);

-- Trigger to keep search_vector up to date
CREATE OR REPLACE FUNCTION products_search_vector_update() RETURNS TRIGGER AS $$
BEGIN
    NEW.search_vector :=
        setweight(to_tsvector('english', COALESCE(NEW.name, '')), 'A') ||
        setweight(to_tsvector('english', COALESCE(NEW.description, '')), 'B') ||
        setweight(to_tsvector('english', COALESCE(NEW.category, '')), 'C') ||
        setweight(to_tsvector('english', COALESCE(NEW.sku, '')), 'D');
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_products_search ON products;
CREATE TRIGGER trg_products_search
    BEFORE INSERT OR UPDATE ON products
    FOR EACH ROW EXECUTE FUNCTION products_search_vector_update();

-- GIN index for fast full-text search
CREATE INDEX IF NOT EXISTS idx_products_search ON products USING GIN (search_vector);
CREATE INDEX IF NOT EXISTS idx_products_category ON products (category);
CREATE INDEX IF NOT EXISTS idx_products_price ON products (price);
CREATE INDEX IF NOT EXISTS idx_products_active ON products (is_active);

-- Users table
CREATE TABLE IF NOT EXISTS users (
    id SERIAL PRIMARY KEY,
    username TEXT NOT NULL UNIQUE,
    email TEXT NOT NULL UNIQUE,
    full_name TEXT,
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMP DEFAULT NOW(),
    search_vector TSVECTOR
);

CREATE OR REPLACE FUNCTION users_search_vector_update() RETURNS TRIGGER AS $$
BEGIN
    NEW.search_vector :=
        setweight(to_tsvector('english', COALESCE(NEW.username, '')), 'A') ||
        setweight(to_tsvector('english', COALESCE(NEW.email, '')), 'B') ||
        setweight(to_tsvector('english', COALESCE(NEW.full_name, '')), 'C');
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_users_search ON users;
CREATE TRIGGER trg_users_search
    BEFORE INSERT OR UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION users_search_vector_update();

CREATE INDEX IF NOT EXISTS idx_users_search ON users USING GIN (search_vector);
CREATE INDEX IF NOT EXISTS idx_users_active ON users (is_active);

-- Sample data
INSERT INTO products (name, description, category, price, sku) VALUES
    ('Wireless Mouse', 'Ergonomic wireless mouse with USB receiver', 'Electronics', 29.99, 'WM-001'),
    ('Mechanical Keyboard', 'RGB mechanical keyboard with Cherry MX switches', 'Electronics', 149.99, 'MK-002'),
    ('Standing Desk', 'Adjustable height standing desk', 'Furniture', 499.99, 'SD-003'),
    ('Monitor Arm', 'Dual monitor arm mount', 'Accessories', 89.99, 'MA-004'),
    ('USB-C Hub', '7-in-1 USB-C hub with HDMI', 'Electronics', 59.99, 'UH-005')
ON CONFLICT DO NOTHING;

INSERT INTO users (username, email, full_name) VALUES
    ('johndoe', 'john@example.com', 'John Doe'),
    ('janedoe', 'jane@example.com', 'Jane Doe'),
    ('bobsmith', 'bob@example.com', 'Bob Smith')
ON CONFLICT DO NOTHING;
"""


def setup_database():
    """Create tables, indexes, triggers, and seed data."""
    with get_db_connection() as conn:
        with conn.cursor() as cur:
            cur.execute(SETUP_SQL)
        conn.commit()
    print("Database setup complete.")


